SELECT count 
FROM cell_data 
WHERE cell_type_id = 0;

SELECT AVG(quality_score) AS average_quality_score
FROM cell_data
WHERE cell_type_id = 0 AND annotation_level_id = 1;

SELECT laterality_name
FROM laterality
WHERE laterality_id = 1;

SELECT cell_type_name
FROM cell_types
WHERE cell_type_id = 1;
